	require.NotEmpty(t, output)
	require.Contains(t, output, "policy_evaluation")
	require.Contains(t, output, policyKey)

	// Verify JSON format
	var logEntry map[string]interface{}
	err := json.Unmarshal([]byte(output), &logEntry)
	require.NoError(t, err)
}

func TestLogEvaluationWithSelectorCache(t *testing.T) {
	buffer := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.InfoLevel, buffer)

	ctx := context.Background()
	policyKey := "policy:cache:test"

	// Create a mock SelectorCache (can be nil for this test, but we're testing the field)
	var sc *SelectorCache // nil is acceptable

	logger.LogEvaluation(ctx, policyKey, sc, nil)

	output := buffer.String()
	require.NotEmpty(t, output)
	require.Contains(t, output, "policy_evaluation")
}

func TestSetLogLevel(t *testing.T) {
	buffer := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.InfoLevel, buffer)

	require.Equal(t, logrus.InfoLevel, logger.GetLogLevel())

	logger.SetLogLevel(logrus.DebugLevel)
	require.Equal(t, logrus.DebugLevel, logger.GetLogLevel())

	logger.SetLogLevel(logrus.WarnLevel)
	require.Equal(t, logrus.WarnLevel, logger.GetLogLevel())
}

func TestLogDecisionWithoutLogging(t *testing.T) {
	buffer := &bytes.Buffer{}
	// Create logger with higher level than what we'll try to log
	logger := NewPolicyAuditLogger(logrus.ErrorLevel, buffer)

	identityLabels := labels.ParseLabelArray("app=web")
	testIdentity := identity.Identity{
		ID:     identity.NumericIdentity(1003),
		Labels: identityLabels,
	}

	// Try to log at info level when logger is at error level
	logger.LogDecision(&testIdentity, "test-policy", PolicyDecisionAllow, "should not appear")

	// Buffer should still be empty or minimal since we're not at the right log level
	output := buffer.String()
	// Note: Due to logrus configuration, there might still be output from the logger itself
	// but the important fields we're testing might not be present
}

func TestThreadSafety(t *testing.T) {
	buffer := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.InfoLevel, buffer)

	done := make(chan bool)

	// Launch multiple goroutines logging decisions
	for i := 0; i < 5; i++ {
		go func(id int) {
			identityLabels := labels.ParseLabelArray("app=web")
			testIdentity := identity.Identity{
				ID:     identity.NumericIdentity(2000 + id),
				Labels: identityLabels,
			}
			logger.LogDecision(&testIdentity, "policy", PolicyDecisionAllow, "test")
			done <- true
		}(i)
	}

	// Wait for all goroutines to complete
	for i := 0; i < 5; i++ {
		<-done
	}

	output := buffer.String()
	require.NotEmpty(t, output)
}

func TestPolicyDecisionString(t *testing.T) {
	require.Equal(t, "ALLOW", PolicyDecisionAllow.String())
	require.Equal(t, "DENY", PolicyDecisionDeny.String())

	var unknown PolicyDecision = 999
	require.Equal(t, "UNKNOWN", unknown.String())
}

func TestLogDecisionWithNilPolicy(t *testing.T) {
	buffer := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.InfoLevel, buffer)

	identityLabels := labels.ParseLabelArray("app=web")
	testIdentity := identity.Identity{
		ID:     identity.NumericIdentity(1004),
		Labels: identityLabels,
	}

	// Log with nil policy
	logger.LogDecision(&testIdentity, nil, PolicyDecisionAllow, "no policy")

	output := buffer.String()
	require.NotEmpty(t, output)
	require.Contains(t, output, "ALLOW")
}

func TestLogEvaluationWithNilResult(t *testing.T) {
	buffer := &bytes.Buffer{}
	logger := NewPolicyAuditLogger(logrus.InfoLevel, buffer)

	ctx := context.Background()

	// Log with nil result
	logger.LogEvaluation(ctx, "policy:key", nil, nil)

	output := buffer.String()
	require.NotEmpty(t, output)
	require.Contains(t, output, "policy_evaluation")
}

